import { Router, Request, Response } from 'express';
import type { Router as RouterType } from 'express';
import crypto from 'crypto';
import { z } from 'zod';
import { pool } from '../db/client.js';
import { authMiddleware } from '../middleware/auth.js';
import { ERROR_CODES, HTTP_STATUS } from '@ship/shared';
import { logAuditEvent } from '../services/audit.js';

const router: RouterType = Router();

function successResponse<T>(res: Response, status: number, data: T): void {
  res.status(status).json({ success: true, data });
}

function errorResponse(
  res: Response,
  status: number,
  code: string,
  message: string,
  details?: unknown
): void {
  res.status(status).json({
    success: false,
    error: {
      code,
      message,
      ...(details !== undefined ? { details } : {}),
    },
  });
}

// Generate a secure API token with "ship_" prefix
function generateApiToken(): { token: string; hash: string; prefix: string } {
  const randomBytes = crypto.randomBytes(32).toString('hex');
  const token = `ship_${randomBytes}`;
  const hash = crypto.createHash('sha256').update(token).digest('hex');
  const prefix = token.substring(0, 12);
  return { token, hash, prefix };
}

// Hash a token for comparison
export function hashToken(token: string): string {
  return crypto.createHash('sha256').update(token).digest('hex');
}

const createTokenSchema = z.object({
  name: z.string().trim().min(1).max(100),
  expires_in_days: z.number().int().positive().max(3650).optional(),
});

async function requireTokenOwnership(req: Request, res: Response, tokenId: string): Promise<{ id: string; name: string } | null> {
  const tokenResult = await pool.query(
    `SELECT id, name
     FROM api_tokens
     WHERE id = $1 AND user_id = $2 AND workspace_id = $3`,
    [tokenId, req.userId, req.workspaceId]
  );

  if (tokenResult.rows.length === 0) {
    errorResponse(res, HTTP_STATUS.NOT_FOUND, ERROR_CODES.NOT_FOUND, 'API token not found');
    return null;
  }

  return tokenResult.rows[0];
}

// POST /api/api-tokens - Generate a new API token
router.post('/', authMiddleware, async (req: Request, res: Response): Promise<void> => {
  const parseResult = createTokenSchema.safeParse(req.body);

  if (!parseResult.success) {
    errorResponse(res, HTTP_STATUS.BAD_REQUEST, ERROR_CODES.VALIDATION_ERROR, 'Invalid request', parseResult.error.flatten());
    return;
  }

  const { name, expires_in_days } = parseResult.data;

  try {
    const existingResult = await pool.query(
      `SELECT id FROM api_tokens
       WHERE user_id = $1 AND workspace_id = $2 AND name = $3 AND revoked_at IS NULL`,
      [req.userId, req.workspaceId, name]
    );

    if (existingResult.rows.length > 0) {
      errorResponse(
        res,
        HTTP_STATUS.CONFLICT,
        ERROR_CODES.ALREADY_EXISTS,
        `An active token named "${name}" already exists. Revoke it first or choose a different name.`
      );
      return;
    }

    const { token, hash, prefix } = generateApiToken();
    const expiresAt = expires_in_days ? new Date(Date.now() + expires_in_days * 24 * 60 * 60 * 1000) : null;

    const result = await pool.query(
      `INSERT INTO api_tokens (user_id, workspace_id, name, token_hash, token_prefix, expires_at)
       VALUES ($1, $2, $3, $4, $5, $6)
       RETURNING id, name, token_prefix, expires_at, created_at`,
      [req.userId, req.workspaceId, name, hash, prefix, expiresAt]
    );

    await logAuditEvent({
      workspaceId: req.workspaceId,
      actorUserId: req.userId!,
      action: 'api_token.created',
      resourceType: 'api_token',
      resourceId: result.rows[0].id,
      details: { name, token_prefix: prefix, expires_at: expiresAt, auth_method: req.isApiToken ? 'api_token' : 'session' },
      req,
    });

    successResponse(res, HTTP_STATUS.CREATED, {
      id: result.rows[0].id,
      name: result.rows[0].name,
      token,
      token_prefix: result.rows[0].token_prefix,
      expires_at: result.rows[0].expires_at,
      created_at: result.rows[0].created_at,
      warning: 'Save this token now. It will not be shown again.',
    });
  } catch (error) {
    console.error('Create API token error:', error);
    errorResponse(res, HTTP_STATUS.INTERNAL_SERVER_ERROR, ERROR_CODES.INTERNAL_ERROR, 'Failed to create API token');
  }
});

// GET /api/api-tokens - List user's API tokens (never returns the actual token)
router.get('/', authMiddleware, async (req: Request, res: Response): Promise<void> => {
  try {
    const result = await pool.query(
      `SELECT id, name, token_prefix, last_used_at, expires_at, revoked_at, created_at
       FROM api_tokens
       WHERE user_id = $1 AND workspace_id = $2
       ORDER BY created_at DESC`,
      [req.userId, req.workspaceId]
    );

    successResponse(
      res,
      HTTP_STATUS.OK,
      result.rows.map(row => ({
        id: row.id,
        name: row.name,
        token_prefix: row.token_prefix,
        last_used_at: row.last_used_at,
        expires_at: row.expires_at,
        is_active: !row.revoked_at && (!row.expires_at || new Date(row.expires_at) > new Date()),
        revoked_at: row.revoked_at,
        created_at: row.created_at,
      }))
    );
  } catch (error) {
    console.error('List API tokens error:', error);
    errorResponse(res, HTTP_STATUS.INTERNAL_SERVER_ERROR, ERROR_CODES.INTERNAL_ERROR, 'Failed to list API tokens');
  }
});

// PATCH /api/api-tokens/:id - Rename an API token
router.patch('/:id', authMiddleware, async (req: Request, res: Response): Promise<void> => {
  const tokenId = String(req.params.id);
  const bodySchema = z.object({ name: z.string().trim().min(1).max(100) });
  const parseResult = bodySchema.safeParse(req.body);

  if (!parseResult.success) {
    errorResponse(res, HTTP_STATUS.BAD_REQUEST, ERROR_CODES.VALIDATION_ERROR, 'Invalid request', parseResult.error.flatten());
    return;
  }

  try {
    const existing = await requireTokenOwnership(req, res, tokenId);
    if (!existing) return;

    const { name } = parseResult.data;

    const conflict = await pool.query(
      `SELECT id FROM api_tokens
       WHERE user_id = $1 AND workspace_id = $2 AND name = $3 AND revoked_at IS NULL AND id <> $4`,
      [req.userId, req.workspaceId, name, tokenId]
    );

    if (conflict.rows.length > 0) {
      errorResponse(res, HTTP_STATUS.CONFLICT, ERROR_CODES.ALREADY_EXISTS, `An active token named "${name}" already exists.`);
      return;
    }

    const updated = await pool.query(
      `UPDATE api_tokens
       SET name = $1
       WHERE id = $2
       RETURNING id, name, token_prefix, expires_at, last_used_at, revoked_at, created_at`,
      [name, tokenId]
    );

    await logAuditEvent({
      workspaceId: req.workspaceId,
      actorUserId: req.userId!,
      action: 'api_token.updated',
      resourceType: 'api_token',
      resourceId: tokenId,
      details: { previous_name: existing.name, name },
      req,
    });

    successResponse(res, HTTP_STATUS.OK, updated.rows[0]);
  } catch (error) {
    console.error('Update API token error:', error);
    errorResponse(res, HTTP_STATUS.INTERNAL_SERVER_ERROR, ERROR_CODES.INTERNAL_ERROR, 'Failed to update API token');
  }
});

// DELETE /api/api-tokens/:id - Revoke an API token
router.delete('/:id', authMiddleware, async (req: Request, res: Response): Promise<void> => {
  const tokenId = String(req.params.id);

  try {
    const token = await requireTokenOwnership(req, res, tokenId);
    if (!token) return;

    const revoked = await pool.query(
      `UPDATE api_tokens
       SET revoked_at = NOW()
       WHERE id = $1 AND revoked_at IS NULL
       RETURNING id, revoked_at`,
      [tokenId]
    );

    if (revoked.rows.length === 0) {
      errorResponse(res, HTTP_STATUS.CONFLICT, ERROR_CODES.ALREADY_EXISTS, 'API token is already revoked');
      return;
    }

    await logAuditEvent({
      workspaceId: req.workspaceId,
      actorUserId: req.userId!,
      action: 'api_token.revoked',
      resourceType: 'api_token',
      resourceId: tokenId,
      details: { name: token.name, auth_method: req.isApiToken ? 'api_token' : 'session' },
      req,
    });

    successResponse(res, HTTP_STATUS.OK, { message: 'API token revoked' });
  } catch (error) {
    console.error('Revoke API token error:', error);
    errorResponse(res, HTTP_STATUS.INTERNAL_SERVER_ERROR, ERROR_CODES.INTERNAL_ERROR, 'Failed to revoke API token');
  }
});

export default router;

