async function ensureUniqueTokenName(req: Request, res: Response, name: string, tokenId?: string): Promise<boolean> {
  const params: Array<string | undefined> = [req.userId, req.workspaceId, name];
  const query = tokenId
    ? `SELECT id FROM api_tokens
       WHERE user_id = $1 AND workspace_id = $2 AND name = $3 AND revoked_at IS NULL AND id <> $4`
    : `SELECT id FROM api_tokens
       WHERE user_id = $1 AND workspace_id = $2 AND name = $3 AND revoked_at IS NULL`;

  if (tokenId) params.push(tokenId);

  const conflict = await pool.query(query, params);
  if (conflict.rows.length > 0) {
    errorResponse(res, HTTP_STATUS.CONFLICT, ERROR_CODES.ALREADY_EXISTS, `An active token named "${name}" already exists.`);
    return false;
  }

  return true;
}

