import { test, expect } from './fixtures/isolated-env'

async function getCsrfToken(page: import('@playwright/test').Page, apiUrl = '') {
  const response = await page.request.get(`${apiUrl}/api/csrf-token`)
  expect(response.ok()).toBe(true)
  return (await response.json()) as { token: string }
}

function getSessionCookie(setCookieHeader: string | undefined): string {
  const sessionCookie = setCookieHeader?.match(/session_id=[^;]+/)?.[0]
  expect(sessionCookie, 'session_id cookie should be issued').toBeTruthy()
  return sessionCookie!
}

test.describe('Critical Blocker: Session Authentication', () => {
  test('login issues a session cookie usable by /api/auth/me', async ({ page, apiServer }) => {
    const csrfToken = (await getCsrfToken(page, apiServer.url)).token
    const loginResponse = await page.request.post(`${apiServer.url}/api/auth/login`, {
      headers: { 'x-csrf-token': csrfToken },
      data: { email: 'dev@ship.local', password: 'admin123' },
    })

    expect(loginResponse.status()).toBe(200)
    const setCookieHeader = loginResponse.headers()['set-cookie'] ?? ''
    expect(setCookieHeader).toContain('session_id=')
    expect(setCookieHeader).toContain('HttpOnly')
    expect(setCookieHeader).toContain('SameSite=Strict')

    const sessionCookie = getSessionCookie(loginResponse.headers()['set-cookie'])

    const meResponse = await page.request.get(`${apiServer.url}/api/auth/me`, {
      headers: { Cookie: sessionCookie },
    })

    expect(meResponse.status()).toBe(200)
    const body = await meResponse.json()
    expect(body.success).toBe(true)
    expect(body.data.user.email).toBe('dev@ship.local')
  })

  test('expired /api/auth/me session returns 401 SESSION_EXPIRED', async ({ page, apiServer }) => {
    const expiredResponse = await page.request.get(`${apiServer.url}/api/auth/me`, {
      headers: { Cookie: 'session_id=expired-session-id' },
    })

    expect(expiredResponse.status()).toBe(401)
    const body = await expiredResponse.json()
    expect(body.success).toBe(false)
    expect(body.error.code).toBe('SESSION_EXPIRED')
  })

  test('GET /api/csrf-token is callable with and without auth cookies', async ({ page, apiServer }) => {
    const anonResponse = await page.request.get(`${apiServer.url}/api/csrf-token`)
    expect(anonResponse.ok()).toBe(true)
    const anonBody = await anonResponse.json()
    expect(anonBody.token).toBeTruthy()

    const csrfToken = (await getCsrfToken(page, apiServer.url)).token
    const loginResponse = await page.request.post(`${apiServer.url}/api/auth/login`, {
      headers: { 'x-csrf-token': csrfToken },
      data: { email: 'dev@ship.local', password: 'admin123' },
    })

    const sessionCookie = getSessionCookie(loginResponse.headers()['set-cookie'])
    const authedResponse = await page.request.get(`${apiServer.url}/api/csrf-token`, {
      headers: { Cookie: sessionCookie },
    })
    expect(authedResponse.ok()).toBe(true)
    const authedBody = await authedResponse.json()
    expect(authedBody.token).toBeTruthy()
  })

  test('Bearer token auth bypasses cookie-based session expectations and still reaches auth middleware', async ({ page, apiServer }) => {
    const response = await page.request.get(`${apiServer.url}/api/auth/me`, {
      headers: { Authorization: 'Bearer ship_test_token' },
    })

    expect([200, 401]).toContain(response.status())
    expect(response.headers()['set-cookie'] ?? '').not.toContain('session_id=')
    if (response.status() === 401) {
      const body = await response.json()
      expect(body.success).toBe(false)
      expect(body.error.code).toBe('UNAUTHORIZED')
    }
  })
})


test.describe('Critical Blocker: Rate Limiting Expectations', () => {
  test('authenticated session requests are not rate limited immediately', async ({ page, apiServer }) => {
    const csrfToken = (await getCsrfToken(page, apiServer.url)).token
    const loginResponse = await page.request.post(`${apiServer.url}/api/auth/login`, {
      headers: { 'x-csrf-token': csrfToken },
      data: { email: 'dev@ship.local', password: 'admin123' },
    })
    const sessionCookie = getSessionCookie(loginResponse.headers()['set-cookie'])

    const responses = await Promise.all(
      Array.from({ length: 3 }, () =>
        page.request.get(`${apiServer.url}/api/auth/me`, {
          headers: { Cookie: sessionCookie },
        })
      )
    )

    for (const response of responses) {
      expect(response.status()).toBe(200)
    }
  })

  test('Bearer-authenticated requests are exempt from rate limiting', async ({ page, apiServer }) => {
    const responses = await Promise.all(
      Array.from({ length: 3 }, () =>
        page.request.get(`${apiServer.url}/api/auth/me`, {
          headers: { Authorization: 'Bearer ship_test_token' },
        })
      )
    )

    for (const response of responses) {
      expect(response.status()).not.toBe(429)
    }
  })
})

