it('should set a usable session cookie that works with /api/auth/me', async () => {
  const loginRes = await loginWithCsrf(testEmail, testPassword)
  const cookies = getCookiesArray(loginRes.headers['set-cookie'])
  const sessionCookie = cookies.find((c: string) => c.startsWith('session_id='))?.split(';')[0]

  expect(sessionCookie).toBeDefined()

  const meRes = await request(app)
    .get('/api/auth/me')
    .set('Cookie', sessionCookie || '')

  expect(meRes.status).toBe(200)
  expect(meRes.body.success).toBe(true)
  expect(meRes.body.data.user).toMatchObject({
    id: testUserId,
    email: testEmail,
  })
  expect(meRes.body.data.currentWorkspace).toBeDefined()
  expect(meRes.body.data.workspaces).toBeInstanceOf(Array)
})

