    36	  impersonatingUserId?: string | null;
    37	}
    38	
    39	function getRequestContext(req?: Request): { ipAddress: string | null; userAgent: string | null } {
    40	  return {
    41	    ipAddress: req?.ip || req?.socket?.remoteAddress || null,
    42	    userAgent: req?.get('user-agent') || null,
