    87	      }
    88	
    89	      // Attach token info to request
    90	      req.userId = tokenData.userId;
    91	      req.workspaceId = tokenData.workspaceId;
    92	      req.isSuperAdmin = tokenData.isSuperAdmin;
    93	      req.isApiToken = true;
    94	
    95	      next();
    96	      return;
    97	    } catch (error) {
    98	      console.error('API token auth error:', error);
