   220	      });
   221	    }
   222	
   223	    // Attach session info to request
   224	    req.sessionId = session.id;
   225	    req.userId = session.user_id;
   226	    req.workspaceId = session.workspace_id;
   227	    req.isSuperAdmin = session.is_super_admin;
   228	
   229	    next();
   230	  } catch (error) {
   231	    console.error('Auth middleware error:', error);
   232	    res.status(HTTP_STATUS.INTERNAL_SERVER_ERROR).json({
   233	      success: false,
   234	      error: {
   235	        code: ERROR_CODES.INTERNAL_ERROR,
   236	        message: 'Authentication failed',
   237	      },
   238	    });
   239	  }
   240	}
   241	
   242	// Middleware that requires super-admin access
   243	export async function superAdminMiddleware(
   244	  req: Request,
   245	  res: Response,
   246	  next: NextFunction
   247	): Promise<void> {
   248	  if (!req.isSuperAdmin) {
   249	    res.status(HTTP_STATUS.FORBIDDEN).json({
   250	      success: false,
   251	      error: {
   252	        code: ERROR_CODES.FORBIDDEN,
   253	        message: 'Super-admin access required',
   254	      },
   255	    });
   256	    return;
   257	  }
   258	
   259	  next();
   260	}","total_lines":373}

