    12	// Generate a secure API token with "ship_" prefix
    13	function generateApiToken(): { token: string; hash: string; prefix: string } {
    14	  const randomBytes = crypto.randomBytes(32).toString('hex');
    15	  const token = `ship_${randomBytes}`;
    16	  const hash = crypto.createHash('sha256').update(token).digest('hex');
    17	  const prefix = token.substring(0, 12); // "ship_" + first 7 chars
    18	  return { token, hash, prefix };
    19	}
    20	
    21	// Hash a token for comparison
    22	export function hashToken(token: string): string {
    23	  return crypto.createHash('sha256').update(token).digest('hex');
    24	}
    25	
    26	const createTokenSchema = z.object({
    27	  name: z.string().min(1).max(100),
    28	  expires_in_days: z.number().int().positive().optional(), // NULL = never expires
    29	});
    30	
    31	// POST /api/api-tokens - Generate a new API token
    32	router.post('/', authMiddleware, async (req: Request, res: Response): Promise<void> => {
    33	  const parseResult = createTokenSchema.safeParse(req.body);
    34	
    35	  if (!parseResult.success) {
    36	    res.status(HTTP_STATUS.BAD_REQUEST).json({
    37	      success: false,
    38	      error: {
    39	        code: ERROR_CODES.VALIDATION_ERROR,
    40	        message: 'Invalid request',
    41	        details: parseResult.error.flatten(),
    42	      },
    43	    });
    44	    return;
    45	  }
    46	
    47	  const { name, expires_in_days } = parseResult.data;
    48	
    49	  try {
    50	    // Check if token with same name already exists for this user/workspace
    51	    const existingResult = await pool.query(
    52	      `SELECT id FROM api_tokens
    53	       WHERE user_id = $1 AND workspace_id = $2 AND name = $3 AND revoked_at IS NULL`,
    54	      [req.userId, req.workspaceId, name]
    55	    );
    56	
    57	    if (existingResult.rows.length > 0) {
    58	      res.status(HTTP_STATUS.CONFLICT).json({
    59	        success: false,
    60	        error: {
    61	          code: ERROR_CODES.ALREADY_EXISTS,
    62	          message: `An active token named "${name}" already exists. Revoke it first or choose a different name.`,
    63	        },
    64	      });
    65	      return;
    66	    }
    67	
    68	    const { token, hash, prefix } = generateApiToken();
    69	    const expiresAt = expires_in_days
    70	      ? new Date(Date.now() + expires_in_days * 24 * 60 * 60 * 1000)
    71	      : null;
