    73	    const result = await pool.query(
    74	      `INSERT INTO api_tokens (user_id, workspace_id, name, token_hash, token_prefix, expires_at)
    75	       VALUES ($1, $2, $3, $4, $5, $6)
    76	       RETURNING id, name, token_prefix, expires_at, created_at`,
    77	      [req.userId, req.workspaceId, name, hash, prefix, expiresAt]
    78	    );
