import { Request, Response, NextFunction } from 'express';
import crypto from 'crypto';
import { pool } from '../db/client.js';
import { SESSION_TIMEOUT_MS, ABSOLUTE_SESSION_TIMEOUT_MS, ERROR_CODES, HTTP_STATUS } from '@ship/shared';
import { auditAuthEvent, auditTokenEvent } from '../services/audit.js';

// Extend Express Request to include session info

declare global {
  namespace Express {
    interface Request {
      sessionId?: string;
      userId?: string;
      workspaceId?: string;
      isSuperAdmin?: boolean;
      isApiToken?: boolean;
    }
  }
}

function hashToken(token: string): string {
  return crypto.createHash('sha256').update(token).digest('hex');
}

async function validateApiToken(token: string): Promise<{
  userId: string;
  workspaceId: string;
  isSuperAdmin: boolean;
  tokenId: string;
} | null> {
  const tokenHash = hashToken(token);
  const result = await pool.query(
    `SELECT t.id, t.user_id, t.workspace_id, t.expires_at, t.revoked_at, u.is_super_admin
     FROM api_tokens t
     JOIN users u ON t.user_id = u.id
     WHERE t.token_hash = $1`,
    [tokenHash]
  );
  const tokenRow = result.rows[0];
  if (!tokenRow || tokenRow.revoked_at) return null;
  if (tokenRow.expires_at && new Date(tokenRow.expires_at) < new Date()) return null;

  await pool.query('UPDATE api_tokens SET last_used_at = NOW() WHERE id = $1', [tokenRow.id]);
  await auditTokenEvent('api_token.used', { actorUserId: tokenRow.user_id, workspaceId: tokenRow.workspace_id }, { type: 'api_token', id: tokenRow.id });

  return {
    userId: tokenRow.user_id,
    workspaceId: tokenRow.workspace_id,
    isSuperAdmin: tokenRow.is_super_admin,
    tokenId: tokenRow.id,
  };
}

type ErrorCodeKey = keyof typeof ERROR_CODES;

function jsonError(res: Response, status: number, code: ErrorCodeKey, message: string): void {
  res.status(status).json({ success: false, error: { code: ERROR_CODES[code], message } });
}

export async function authMiddleware(req: Request, res: Response, next: NextFunction): Promise<void> {
  const authHeader = req.headers?.authorization;
  if (authHeader?.startsWith('Bearer ')) {
    try {
      const tokenData = await validateApiToken(authHeader.slice(7));
      if (!tokenData) {
        jsonError(res, HTTP_STATUS.UNAUTHORIZED, 'UNAUTHORIZED', 'Invalid or expired API token');
        return;
      }
      req.userId = tokenData.userId;
      req.workspaceId = tokenData.workspaceId;
      req.isSuperAdmin = tokenData.isSuperAdmin;
      req.isApiToken = true;
      return next();
    } catch (error) {
      console.error('API token auth error:', error);
      jsonError(res, HTTP_STATUS.INTERNAL_SERVER_ERROR, 'INTERNAL_ERROR', 'Authentication failed');
      return;
    }
  }

  const sessionId = req.cookies?.session_id;
  if (!sessionId) {
    jsonError(res, HTTP_STATUS.UNAUTHORIZED, 'UNAUTHORIZED', 'No session found');
    return;
  }

  try {
    const result = await pool.query(
      `SELECT s.id, s.user_id, s.workspace_id, s.expires_at, s.last_activity, s.created_at, u.is_super_admin
       FROM sessions s
       JOIN users u ON s.user_id = u.id
       WHERE s.id = $1`,
      [sessionId]
    );
    const session = result.rows[0];
    if (!session) {
      jsonError(res, HTTP_STATUS.UNAUTHORIZED, 'UNAUTHORIZED', 'Invalid session');
      return;
    }

    const now = new Date();
    const lastActivity = new Date(session.last_activity);
    const createdAt = new Date(session.created_at);
    const inactivityMs = now.getTime() - lastActivity.getTime();
    const sessionAgeMs = now.getTime() - createdAt.getTime();

    if (sessionAgeMs > ABSOLUTE_SESSION_TIMEOUT_MS) {
      await pool.query('DELETE FROM sessions WHERE id = $1', [sessionId]);
      await auditAuthEvent('session.expired', { req, workspaceId: session.workspace_id, actorUserId: session.user_id }, { reason: 'absolute_timeout', sessionId });
      jsonError(res, HTTP_STATUS.UNAUTHORIZED, 'SESSION_EXPIRED', 'Session expired. Please log in again.');
      return;
    }

    if (inactivityMs > SESSION_TIMEOUT_MS) {
      await pool.query('DELETE FROM sessions WHERE id = $1', [sessionId]);
      await auditAuthEvent('session.expired', { req, workspaceId: session.workspace_id, actorUserId: session.user_id }, { reason: 'inactivity_timeout', sessionId });
      jsonError(res, HTTP_STATUS.UNAUTHORIZED, 'SESSION_EXPIRED', 'Session expired due to inactivity');
      return;
    }

    if (session.workspace_id && !session.is_super_admin) {
      const membershipResult = await pool.query(
        'SELECT id, role FROM workspace_memberships WHERE workspace_id = $1 AND user_id = $2',
        [session.workspace_id, session.user_id]
      );
      if (!membershipResult.rows[0]) {
        await pool.query('DELETE FROM sessions WHERE id = $1', [sessionId]);
        await auditAuthEvent('auth.login_failed', { req, workspaceId: session.workspace_id, actorUserId: session.user_id }, { reason: 'workspace_access_revoked', sessionId });
        jsonError(res, HTTP_STATUS.FORBIDDEN, 'FORBIDDEN', 'Access to this workspace has been revoked');
        return;
      }
    }

    await pool.query('UPDATE sessions SET last_activity = $1 WHERE id = $2', [now, sessionId]);
    const COOKIE_REFRESH_THRESHOLD_MS = 60 * 1000;
    if (inactivityMs > COOKIE_REFRESH_THRESHOLD_MS) {
      res.cookie('session_id', sessionId, {
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production',
        sameSite: 'strict',
        maxAge: SESSION_TIMEOUT_MS,
        path: '/',
      });
    }

    req.sessionId = session.id;
    req.userId = session.user_id;
    req.workspaceId = session.workspace_id;
    req.isSuperAdmin = session.is_super_admin;
    next();
  } catch (error) {
    console.error('Auth middleware error:', error);
    jsonError(res, HTTP_STATUS.INTERNAL_SERVER_ERROR, 'INTERNAL_ERROR', 'Authentication failed');
  }
}

export async function superAdminMiddleware(req: Request, res: Response, next: NextFunction): Promise<void> {
  if (!req.isSuperAdmin) {
    jsonError(res, HTTP_STATUS.FORBIDDEN, 'FORBIDDEN', 'Super-admin access required');
    return;
  }
  next();
}

export async function workspaceAdminMiddleware(req: Request, res: Response, next: NextFunction): Promise<void> {
  if (req.isSuperAdmin) return next();
  const workspaceId = req.params.id || req.workspaceId;
  if (!workspaceId) {
    jsonError(res, HTTP_STATUS.BAD_REQUEST, 'VALIDATION_ERROR', 'Workspace ID required');
    return;
  }
  try {
    const result = await pool.query('SELECT role FROM workspace_memberships WHERE workspace_id = $1 AND user_id = $2', [workspaceId, req.userId]);
    if (!result.rows[0] || result.rows[0].role !== 'admin') {
      jsonError(res, HTTP_STATUS.FORBIDDEN, 'FORBIDDEN', 'Workspace admin access required');
      return;
    }
    next();
  } catch (error) {
    console.error('Workspace admin middleware error:', error);
    jsonError(res, HTTP_STATUS.INTERNAL_SERVER_ERROR, 'INTERNAL_ERROR', 'Authorization check failed');
  }
}

export async function workspaceAccessMiddleware(req: Request, res: Response, next: NextFunction): Promise<void> {
  if (req.isSuperAdmin) return next();
  const workspaceId = req.params.workspaceId || req.workspaceId;
  if (!workspaceId) {
    jsonError(res, HTTP_STATUS.BAD_REQUEST, 'VALIDATION_ERROR', 'Workspace ID required');
    return;
  }
  try {
    const result = await pool.query('SELECT id FROM workspace_memberships WHERE workspace_id = $1 AND user_id = $2', [workspaceId, req.userId]);
    if (!result.rows[0]) {
      jsonError(res, HTTP_STATUS.FORBIDDEN, 'FORBIDDEN', 'Access denied to this workspace');
      return;
    }
    next();
  } catch (error) {
    console.error('Workspace access middleware error:', error);
    jsonError(res, HTTP_STATUS.INTERNAL_SERVER_ERROR, 'INTERNAL_ERROR', 'Authorization check failed');
  }
}

