import { Router, Request, Response } from 'express';
import type { Router as RouterType } from 'express';
import bcrypt from 'bcryptjs';
import crypto from 'crypto';
import { pool } from '../db/client.js';
import { authMiddleware } from '../middleware/auth.js';
import { ERROR_CODES, HTTP_STATUS, SESSION_TIMEOUT_MS, ABSOLUTE_SESSION_TIMEOUT_MS } from '@ship/shared';
import { auditAuthEvent, auditSessionEvent } from '../services/audit.js';

const router: RouterType = Router();

function jsonError(res: Response, status: number, code: keyof typeof ERROR_CODES, message: string): void {
  res.status(status).json({ success: false, error: { code: ERROR_CODES[code], message } });
}

function generateSecureSessionId(): string {
  return crypto.randomBytes(32).toString('hex');
}

function setSessionCookie(res: Response, sessionId: string): void {
  res.cookie('session_id', sessionId, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'strict',
    maxAge: SESSION_TIMEOUT_MS,
    path: '/',
  });
}

function clearSessionCookie(res: Response): void {
  res.clearCookie('session_id', {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'strict',
    path: '/',
  });
}

router.post('/login', async (req: Request, res: Response): Promise<void> => {
  const { email, password } = req.body;

  if (!email || !password) {
    jsonError(res, HTTP_STATUS.BAD_REQUEST, 'VALIDATION_ERROR', 'Email and password are required');
    return;
  }

  try {
    const userResult = await pool.query(
      `SELECT u.id, u.email, u.password_hash, u.name, u.is_super_admin, u.last_workspace_id
       FROM users u
       WHERE LOWER(u.email) = LOWER($1)`,
      [email]
    );

    const user = userResult.rows[0];
    if (!user) {
      await auditAuthEvent('auth.login_failed', { req }, { email, reason: 'user_not_found' });
      jsonError(res, HTTP_STATUS.UNAUTHORIZED, 'INVALID_CREDENTIALS', 'Invalid email or password');
      return;
    }

    if (!user.password_hash) {
      await auditAuthEvent('auth.login_failed', { req, actorUserId: user.id }, { email, reason: 'piv_only_user' });
      jsonError(res, HTTP_STATUS.UNAUTHORIZED, 'INVALID_CREDENTIALS', 'This account uses PIV authentication only');
      return;
    }

    const validPassword = await bcrypt.compare(password, user.password_hash);
    if (!validPassword) {
      await auditAuthEvent('auth.login_failed', { req, actorUserId: user.id }, { email, reason: 'invalid_password' });
      jsonError(res, HTTP_STATUS.UNAUTHORIZED, 'INVALID_CREDENTIALS', 'Invalid email or password');
      return;
    }

    const workspacesResult = await pool.query(
      `SELECT w.id, w.name, wm.role
       FROM workspaces w
       JOIN workspace_memberships wm ON w.id = wm.workspace_id
       WHERE wm.user_id = $1 AND w.archived_at IS NULL
       ORDER BY w.name`,
      [user.id]
    );

    const workspaces = workspacesResult.rows;
    let workspaceId: string | null = null;
    if (user.last_workspace_id && workspaces.some(w => w.id === user.last_workspace_id)) workspaceId = user.last_workspace_id;
    if (!workspaceId && workspaces.length > 0) workspaceId = workspaces[0].id;
    if (!workspaceId && !user.is_super_admin && workspaces.length === 0) {
      await auditAuthEvent('auth.login_failed', { req, actorUserId: user.id }, { email, reason: 'no_workspace_access' });
      jsonError(res, HTTP_STATUS.FORBIDDEN, 'FORBIDDEN', 'You do not have access to any workspaces');
      return;
    }

    const oldSessionId = req.cookies.session_id;
    if (oldSessionId) {
      await pool.query('DELETE FROM sessions WHERE id = $1', [oldSessionId]);
    }

    const sessionId = generateSecureSessionId();
    const expiresAt = new Date(Date.now() + SESSION_TIMEOUT_MS);
    await pool.query(
      `INSERT INTO sessions (id, user_id, workspace_id, expires_at, last_activity, user_agent, ip_address)
       VALUES ($1, $2, $3, $4, $5, $6, $7)`,
      [sessionId, user.id, workspaceId, expiresAt, new Date(), req.get('user-agent') || 'unknown', req.ip || req.socket.remoteAddress || 'unknown']
    );

    if (workspaceId) {
      await pool.query('UPDATE users SET last_workspace_id = $1, updated_at = NOW() WHERE id = $2', [workspaceId, user.id]);
    }

    await auditAuthEvent('auth.login', { req, workspaceId, actorUserId: user.id });
    setSessionCookie(res, sessionId);

    res.json({
      success: true,
      data: {
        user: { id: user.id, email: user.email, name: user.name, isSuperAdmin: user.is_super_admin },
        currentWorkspace: workspaceId ? { id: workspaceId, name: workspaces.find(w => w.id === workspaceId)?.name, role: workspaces.find(w => w.id === workspaceId)?.role } : null,
        workspaces: workspaces.map(w => ({ id: w.id, name: w.name, role: w.role })),
        pendingAccountabilityItems: [],
      },
    });
  } catch (error) {
    console.error('Login error:', error);
    jsonError(res, HTTP_STATUS.INTERNAL_SERVER_ERROR, 'INTERNAL_ERROR', 'Login failed');
  }
});

router.post('/logout', authMiddleware, async (req: Request, res: Response): Promise<void> => {
  try {
    await pool.query('DELETE FROM sessions WHERE id = $1', [req.sessionId]);
    await auditAuthEvent('auth.logout', { req, workspaceId: req.workspaceId, actorUserId: req.userId });
    clearSessionCookie(res);
    res.json({ success: true });
  } catch (error) {
    console.error('Logout error:', error);
    jsonError(res, HTTP_STATUS.INTERNAL_SERVER_ERROR, 'INTERNAL_ERROR', 'Logout failed');
  }
});

router.get('/me', authMiddleware, async (req: Request, res: Response): Promise<void> => {
  try {
    const result = await pool.query(`SELECT id, email, name, is_super_admin FROM users WHERE id = $1`, [req.userId]);
    const user = result.rows[0];
    if (!user) {
      jsonError(res, HTTP_STATUS.NOT_FOUND, 'NOT_FOUND', 'User not found');
      return;
    }

    const workspacesResult = await pool.query(
      `SELECT w.id, w.name, wm.role
       FROM workspaces w
       JOIN workspace_memberships wm ON w.id = wm.workspace_id
       WHERE wm.user_id = $1 AND w.archived_at IS NULL
       ORDER BY w.name`,
      [req.userId]
    );

    let currentWorkspace = null;
    if (req.workspaceId) {
      const currentResult = await pool.query(
        `SELECT w.id, w.name, wm.role
         FROM workspaces w
         LEFT JOIN workspace_memberships wm ON w.id = wm.workspace_id AND wm.user_id = $2
         WHERE w.id = $1`,
        [req.workspaceId, req.userId]
      );
      if (currentResult.rows[0]) currentWorkspace = { id: currentResult.rows[0].id, name: currentResult.rows[0].name, role: currentResult.rows[0].role || 'admin' };
    }

    res.json({
      success: true,
      data: { user: { id: user.id, email: user.email, name: user.name, isSuperAdmin: user.is_super_admin }, currentWorkspace, workspaces: workspacesResult.rows.map(w => ({ id: w.id, name: w.name, role: w.role })), pendingAccountabilityItems: [] },
    });
  } catch (error) {
    console.error('Get me error:', error);
    jsonError(res, HTTP_STATUS.INTERNAL_SERVER_ERROR, 'INTERNAL_ERROR', 'Failed to get user info');
  }
});

router.post('/extend-session', authMiddleware, async (req: Request, res: Response): Promise<void> => {
  try {
    const now = new Date();
    const expiresAt = new Date(now.getTime() + SESSION_TIMEOUT_MS);
    await pool.query(`UPDATE sessions SET last_activity = $1, expires_at = $2 WHERE id = $3`, [now, expiresAt, req.sessionId]);
    await auditSessionEvent('session.refreshed', { req, workspaceId: req.workspaceId, actorUserId: req.userId! }, { sessionId: req.sessionId, expiresAt: expiresAt.toISOString() });
    setSessionCookie(res, req.sessionId!);
    res.json({ success: true, data: { expiresAt: expiresAt.toISOString(), lastActivity: now.toISOString() } });
  } catch (error) {
    console.error('Extend session error:', error);
    jsonError(res, HTTP_STATUS.INTERNAL_SERVER_ERROR, 'INTERNAL_ERROR', 'Failed to extend session');
  }
});

router.get('/session', authMiddleware, async (req: Request, res: Response): Promise<void> => {
  try {
    const result = await pool.query(`SELECT id, created_at, expires_at, last_activity FROM sessions WHERE id = $1`, [req.sessionId]);
    const session = result.rows[0];
    if (!session) {
      jsonError(res, HTTP_STATUS.NOT_FOUND, 'NOT_FOUND', 'Session not found');
      return;
    }

    const createdAt = new Date(session.created_at);
    const absoluteExpiresAt = new Date(createdAt.getTime() + ABSOLUTE_SESSION_TIMEOUT_MS);
    await auditSessionEvent('session.created', { req, workspaceId: req.workspaceId, actorUserId: req.userId }, { sessionId: session.id });

    res.json({ success: true, data: { createdAt: session.created_at, expiresAt: session.expires_at, absoluteExpiresAt: absoluteExpiresAt.toISOString(), lastActivity: session.last_activity } });
  } catch (error) {
    console.error('Get session error:', error);
    jsonError(res, HTTP_STATUS.INTERNAL_SERVER_ERROR, 'INTERNAL_ERROR', 'Failed to get session info');
  }
});

export default router;

