});

const apiLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: isTestEnv ? 10000 : isDevEnv ? 1000 : 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests. Please slow down.' },
  skip: isBearerRequest,
});

